import os
from subprocess import run, PIPE
import sys


def convertDoc(inputFile, outputFile, fileType):
    command = 'soffice --headless --convert-to ' + fileType + ' ' + inputFile + ' --outdir .' + outputFile
    os.chdir(".")

    try:
        print(inputFile + '  was converted to ' + outputFile)
    except Exception as e1:
        print('Error while convering ' + inputFile + '. Error -', file=sys.stderr, flush=True)

    run(command, shell=True, stdin=PIPE, stdout=PIPE, stderr=PIPE)


